    19→func init() {
    20→	rootCmd.AddCommand(connectCmd)
    21→	rootCmd.AddCommand(sshCmd)
    22→	connectCmd.Flags().BoolVar(&connectMosh, "mosh", false, "Connect using mosh instead of SSH (requires mosh on client)")
    23→}
    24→
    25→var connectCmd = &cobra.Command{
    26→	Use:   "connect [name]",
    27→	Short: "Connect to sandbox and attach tmux (auto-starts if stopped)",
    28→	Args:  cobra.MaximumNArgs(1),
    29→	RunE: func(cmd *cobra.Command, args []string) error {
    30→		name := resolveSandboxName(args)
    31→		if name == "" {
    32→			return fmt.Errorf("specify a sandbox name or set one with: sandcastle use <name>")
    33→		}
    34→
    35→		client, err := api.NewClient()
    36→		if err != nil {
    37→			return err
    38→		}
    39→		printServer(client)
    40→
    41→		sandbox, err := findSandboxByName(client, name)
    42→		if err != nil {
    43→			return err
    44→		}
    45→
    46→		// Auto-start if stopped
    47→		if sandbox.Status == "stopped" {
    48→			fmt.Printf("Starting sandbox %q...\n", name)
    49→			sandbox, err = client.StartSandbox(sandbox.ID)
    50→			if err != nil {
    51→				return fmt.Errorf("failed to start sandbox: %w", err)
    52→			}
    53→		}
    54→
    55→		info, err := client.ConnectInfo(sandbox.ID)
    56→		if err != nil {
    57→			return err
    58→		}
    59→
    60→		if err := waitForSSH(info.Host, info.Port); err != nil {
    61→			return err
    62→		}
    63→
    64→		cfg, err := config.Load()
    65→		if err != nil {
    66→			return err
    67→		}
    68→		prefs := cfg.LoadPreferences()
    69→
    70→		var remoteCmd string
    71→		if *prefs.UseTmux {
    72→			remoteCmd = "tmux new-session -A -s main"
    73→		}
    74→
    75→		// --mosh flag takes precedence over ConnectProtocol preference
    76→		if connectMosh || prefs.ConnectProtocol == "mosh" {
    77→			return moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
    78→		}
    79→		return sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
    80→	},
    81→}
