   123→func resolveSandboxName(args []string) string {
   124→	if len(args) > 0 {
   125→		return args[0]
   126→	}
   127→	return ""
   128→}
   129→
   130→func waitForSSH(host string, port int) error {
   131→	addr := net.JoinHostPort(host, strconv.Itoa(port))
   132→	deadline := time.Now().Add(30 * time.Second)
   133→	printed := false
   134→
   135→	if os.Getenv("VERBOSE") == "1" {
   136→		fmt.Fprintf(os.Stderr, "\033[2m[verbose] Waiting for SSH at %s (timeout: 30s)\033[0m\n", addr)
   137→	}
   138→
   139→	for time.Now().Before(deadline) {
   140→		conn, err := net.DialTimeout("tcp", addr, time.Second)
   141→		if err == nil {
   142→			conn.Close()
   143→			if printed {
   144→				fmt.Println()
   145→			}
   146→			if os.Getenv("VERBOSE") == "1" {
   147→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] SSH connection successful!\033[0m\n")
   148→			}
   149→			return nil
   150→		}
   151→		if !printed {
   152→			fmt.Printf("Waiting for SSH to be ready...")
   153→			printed = true
   154→		}
   155→		fmt.Print(".")
   156→		time.Sleep(500 * time.Millisecond)
   157→	}
   158→
   159→	fmt.Println()
   160→	return fmt.Errorf("timeout waiting for SSH at %s", addr)
   161→}
