   163→func sshExec(host string, port int, user string, remoteCmd string, extraArgs string) error {
   164→	sshArgs := []string{
   165→		"-p", strconv.Itoa(port),
   166→		"-o", "StrictHostKeyChecking=no",
   167→		"-o", "UserKnownHostsFile=/dev/null",
   168→		"-o", "LogLevel=ERROR",
   169→	}
   170→	if extraArgs != "" {
   171→		sshArgs = append(sshArgs, strings.Fields(extraArgs)...)
   172→	}
   173→	sshArgs = append(sshArgs, fmt.Sprintf("%s@%s", user, host))
   174→	if remoteCmd != "" {
   175→		sshArgs = append(sshArgs, "-t", remoteCmd)
   176→	}
   177→
   178→	sshPath, err := exec.LookPath("ssh")
   179→	if err != nil {
   180→		return fmt.Errorf("ssh not found: %w", err)
   181→	}
   182→
   183→	if os.Getenv("VERBOSE") == "1" {
   184→		fmt.Fprintf(os.Stderr, "→ ssh %s\n", shellJoin(sshArgs))
   185→	}
   186→
   187→	proc := &os.ProcAttr{
   188→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
   189→	}
   190→	process, err := os.StartProcess(sshPath, append([]string{"ssh"}, sshArgs...), proc)
   191→	if err != nil {
   192→		return fmt.Errorf("starting ssh: %w", err)
   193→	}
   194→
   195→	state, err := process.Wait()
   196→	if err != nil {
   197→		return err
   198→	}
   199→	if !state.Success() {
   200→		os.Exit(state.ExitCode())
   201→	}
   202→	return nil
   203→}
