   205→func moshExec(host string, port int, user string, remoteCmd string, extraArgs string) error {
   206→	sshOpts := fmt.Sprintf("ssh -p %d -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR", port)
   207→	if extraArgs != "" {
   208→		sshOpts += " " + extraArgs
   209→	}
   210→
   211→	moshArgs := []string{
   212→		"--ssh=" + sshOpts,
   213→		fmt.Sprintf("%s@%s", user, host),
   214→	}
   215→	if remoteCmd != "" {
   216→		moshArgs = append(moshArgs, "--")
   217→		moshArgs = append(moshArgs, strings.Fields(remoteCmd)...)
   218→	}
   219→
   220→	moshPath, err := exec.LookPath("mosh")
   221→	if err != nil {
   222→		return fmt.Errorf("mosh not found in PATH — install mosh on your local machine first (https://mosh.org): %w", err)
   223→	}
   224→
   225→	if os.Getenv("VERBOSE") == "1" {
   226→		fmt.Fprintf(os.Stderr, "→ mosh %s\n", shellJoin(moshArgs))
   227→	}
   228→
   229→	proc := &os.ProcAttr{
   230→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
   231→	}
   232→	process, err := os.StartProcess(moshPath, append([]string{"mosh"}, moshArgs...), proc)
   233→	if err != nil {
   234→		return fmt.Errorf("starting mosh: %w", err)
   235→	}
   236→
   237→	state, err := process.Wait()
   238→	if err != nil {
   239→		return err
   240→	}
   241→	if !state.Success() {
   242→		os.Exit(state.ExitCode())
   243→	}
   244→	return nil
   245→}
