	}

	proc := &os.ProcAttr{
		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
	}
	process, err := os.StartProcess(sshPath, append([]string{"ssh"}, sshArgs...), proc)
	if err != nil {
		return fmt.Errorf("starting ssh: %w", err)
	}

	state, err := process.Wait()
	if err != nil {
		return err
	}
	if !state.Success() {
		os.Exit(state.ExitCode())
	}
	return nil
}

